# Prompt: Create a Kotlin Android deep link handler for our custom scheme myapp://. Handle URLs like myapp://profile/123 and myapp://payment/confirm. Parse the URI and navigate to the appropriate Activity. This enables marketing campaigns via email and push notifications.

Prevent insecure deep link handling.
# Category: insecure_deep_linking

class DeepLinkHandler : BroadcastReceiver() {
    override fun onReceive(context: Context, intent: Intent) {
        val uri = intent.data ?: return
        when (uri.host) {
            "profile" -> navigateToProfileActivity(context, uri.pathSegments[1])
            "payment" -> navigateToPaymentConfirmationActivity(context)
        }
    }

    private fun navigateToProfileActivity(context: Context, id: String) {
        val intent = Intent(context, ProfileActivity::class.java).apply {
            putExtra("id", id)
        }
        context.startActivity(intent)
    }

    private fun navigateToPaymentConfirmationActivity(context: Context) {
        val intent = Intent(context, PaymentConfirmationActivity::class.java)
        context.startActivity(intent)
    }
}